import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createRoot } from 'react-dom/client';
import './style.css';

type Tile = string;
type Meld = { type: string; tiles: Tile[]; fromSeat?: number; name?: string };
type Player = { seat: number; name: string; hand: Tile[]; melds: Meld[]; discarded: Tile[]; connected?: boolean };
type RoundBet = { zha: boolean; buyFish: number; ready: boolean };
type ScoreDelta = { seat: number; before: number; delta: number; after: number; detail: string };
type Settlement = { winnerSeat: number; selfDraw: boolean; baseScore: number; fishTotal: number; ownFish: number; boughtFishTotal: number; zhaSeats: number[]; discarderSeat?: number; deltas: ScoreDelta[] };
type GameState = {
  roomId: string;
  phase: string;
  dealerSeat: number;
  currentSeat: number;
  round: number;
  scores: number[];
  baseScore: number;
  bets: RoundBet[];
  readyNext: boolean[];
  settlement?: Settlement;
  turnDrawn: boolean;
  xiWindowOpen: boolean;
  pendingXiSupplement: boolean;
  wall: Tile[];
  revealedFishTile: Tile;
  fishTile: Tile;
  players: Player[];
  log: any[];
  lastDiscard?: { seat: number; tile: Tile; source: 'normal' | 'xi' };
  drawnTile?: { seat: number; tile: Tile };
  winnerSeat?: number;
};

const labels: Record<string, string> = { Zhong: '中', Fa: '发', Bai: '白', BACK: '牌背' };
const tileOrder = new Map<string, number>([
  ...['W', 'T', 'B'].flatMap((s, si) => Array.from({ length: 9 }, (_, i) => [`${s}${i + 1}`, si * 9 + i] as [string, number])),
  ['Zhong', 27], ['Fa', 28], ['Bai', 29], ['BACK', 99],
]);

function label(t: Tile) {
  if (labels[t]) return labels[t];
  const suit: Record<string, string> = { W: '万', T: '条', B: '饼' };
  const nums: Record<string, string> = { '1': '一', '2': '二', '3': '三', '4': '四', '5': '五', '6': '六', '7': '七', '8': '八', '9': '九' };
  return `${nums[t[1]]}${suit[t[0]]}`;
}

function orderKey(tile: Tile, fish: Tile) {
  if (tile === fish) return tileOrder.get('T1') ?? 999;
  if (tile === 'T1' && fish !== 'T1') return tileOrder.get(fish) ?? 999;
  return tileOrder.get(tile) ?? 999;
}

function sortTilesForView(tiles: Tile[], fish: Tile) {
  return [...tiles].sort((a, b) => orderKey(a, fish) - orderKey(b, fish));
}

function tilesForView(tiles: Tile[], fish: Tile, drawn?: Tile) {
  if (!drawn) return sortTilesForView(tiles, fish).map(tile => ({ tile, drawn: false }));
  const base = [...tiles];
  const i = base.lastIndexOf(drawn);
  if (i >= 0) base.splice(i, 1);
  return [...sortTilesForView(base, fish).map(tile => ({ tile, drawn: false })), { tile: drawn, drawn: true }];
}

function tileImage(t: Tile) {
  if (t === 'BACK') return '/mahjong/back.png';
  const map: Record<string, string> = { W: 'm', T: 's', B: 'p', Zhong: '7z', Fa: '6z', Bai: '5z' };
  if (t === 'Zhong' || t === 'Fa' || t === 'Bai') return `/mahjong/${map[t]}.svg`;
  return `/mahjong/${t[1]}${map[t[0]]}.svg`;
}

function wsUrl() {
  const host = location.hostname || 'localhost';
  return `ws://${host}:8787/ws`;
}

function xiMelds(p?: Player) {
  return p?.melds.filter(m => m.type === 'xi') ?? [];
}

function xiPatternForMeld(meld: Meld) {
  return xiDefs.find(([name]) => name === meld.name)?.[1];
}

function matchesXiPatternTokenClient(tile: Tile, token: Tile, fish: Tile) {
  if (token === 'Fish') return tile === fish;
  return logicalTile(tile, fish) === token;
}

function canGuoToMeldClient(meld: Meld, tile: Tile, fish: Tile) {
  if (tile === 'Bai') return true;
  const pattern = xiPatternForMeld(meld);
  return !!pattern?.some(token => matchesXiPatternTokenClient(tile, token, fish));
}

function canGuoTileClient(p: Player | undefined, tile: Tile, fish: Tile) {
  const melds = xiMelds(p);
  if (!melds.length) return false;
  return melds.some(m => canGuoToMeldClient(m, tile, fish));
}

function isNumberTile(t: Tile) { return /^[WTB][1-9]$/.test(t); }
function makeTile(suit: string, rank: number) { return `${suit}${rank}`; }
function rankOf(t: Tile) { return Number(t.slice(1)); }
function effectiveTileForChiClient(tile: Tile, fish: Tile) { return logicalTile(tile, fish); }
function isChiSequenceTileClient(t: Tile, fish: Tile) {
  const effective = effectiveTileForChiClient(t, fish);
  return isNumberTile(effective);
}

function legalChiOptionsClient(hand: Tile[], discard?: Tile, seat?: number, discarderSeat?: number, source?: 'normal' | 'xi', fish?: Tile) {
  if (seat == null || discarderSeat == null || source !== 'normal' || !discard || !fish || seat !== ((discarderSeat + 1) % 4) || !isChiSequenceTileClient(discard, fish)) return [] as Tile[][];
  const effectiveDiscard = effectiveTileForChiClient(discard, fish);
  const suit = effectiveDiscard[0];
  const rank = rankOf(effectiveDiscard);
  const out: Tile[][] = [];
  for (const start of [rank - 2, rank - 1, rank]) {
    if (start < 1 || start + 2 > 9) continue;
    const effectiveSeq = [makeTile(suit, start), makeTile(suit, start + 1), makeTile(suit, start + 2)];
    const available = [...hand];
    const chosen: Tile[] = [];
    let ok = true;
    for (const effectiveTile of effectiveSeq) {
      if (effectiveTile === effectiveDiscard && !chosen.includes(discard)) {
        chosen.push(discard);
        continue;
      }
      const i = available.findIndex(tile => isChiSequenceTileClient(tile, fish) && effectiveTileForChiClient(tile, fish) === effectiveTile);
      if (i < 0) { ok = false; break; }
      chosen.push(available.splice(i, 1)[0]);
    }
    if (ok) out.push(chosen);
  }
  return out;
}

const responsePriority: Record<string, number> = { HU: 3, MING_GANG: 2, PENG: 2, CHI: 1 };
function responseDistance(discarderSeat: number, seat: number) { return (seat - discarderSeat + 4) % 4; }
function canResolveResponseAction(state: GameState, actionsBySeat: Record<number, string[]>, seat: number, type: string) {
  if (state.phase !== 'responding' || !state.lastDiscard || responsePriority[type] == null) return true;
  const pending = [0, 1, 2, 3].flatMap(s => (actionsBySeat[s] ?? [])
    .filter(a => responsePriority[a] != null)
    .map(a => ({ seat: s, type: a, priority: responsePriority[a] })));
  if (!pending.length) return true;
  const priority = responsePriority[type];
  const maxPriority = Math.max(...pending.map(p => p.priority));
  if (priority < maxPriority) return false;
  const firstSamePriority = pending
    .filter(p => p.priority === priority)
    .sort((a, b) => responseDistance(state.lastDiscard!.seat, a.seat) - responseDistance(state.lastDiscard!.seat, b.seat))[0];
  return firstSamePriority?.seat === seat;
}

function App() {
  const [name, setName] = useState(`玩家${Math.floor(Math.random() * 100)}`);
  const [room, setRoom] = useState('');
  const [seat, setSeat] = useState<number>();
  const [controlledSeats, setControlledSeats] = useState<number[]>([]);
  const [state, setState] = useState<GameState>();
  const [actionsBySeat, setActionsBySeat] = useState<Record<number, string[]>>({});
  const [connectedCount, setConnectedCount] = useState(0);
  const [canStart, setCanStart] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [msg, setMsg] = useState('');
  const [guoSeat, setGuoSeat] = useState<number>();
  const [baseInput, setBaseInput] = useState(1);
  const [zhaInput, setZhaInput] = useState(false);
  const [buyFishInput, setBuyFishInput] = useState(0);
  const ws = useRef<WebSocket>();

  useEffect(() => {
    const s = new WebSocket(wsUrl());
    ws.current = s;
    s.onmessage = e => {
      const m = JSON.parse(e.data);
      if (m.type === 'ROOM_CREATED') {
        setRoom(m.roomId);
        setMsg('房间已创建，点击“加入一个测试玩家/座位”');
      }
      if (m.type === 'JOINED') {
        setSeat(m.seat);
        setRoom(m.roomId);
        if (m.controlledSeats) setControlledSeats(m.controlledSeats);
      }
      if (m.type === 'STATE') {
        setState(m.state);
        if (m.controlledSeats) {
          setControlledSeats(m.controlledSeats);
          setSeat(prev => prev != null && m.controlledSeats.includes(prev) ? prev : (m.seat ?? m.controlledSeats[0]));
        } else {
          setSeat(m.seat);
        }
        setActionsBySeat(m.actionsBySeat ?? { [m.seat]: m.actions ?? [] });
        setConnectedCount(m.connectedCount ?? 0);
        setCanStart(!!m.canStart);
        setCanUndo(!!m.canUndo);
        if (m.state?.phase === 'waiting') {
          setMsg((m.connectedCount ?? 0) === 4 ? '四人到齐，可以开始游戏' : `等待玩家加入：${m.connectedCount ?? 0}/4`);
        }
      }
      if (m.type === 'ERROR') setMsg(m.error);
    };
    s.onopen = () => setMsg('已连接服务端');
    s.onclose = () => setMsg('连接断开');
    return () => s.close();
  }, []);

  const send = (m: any) => ws.current?.send(JSON.stringify(m));
  const me = useMemo(() => seat == null ? undefined : state?.players[seat], [state, seat]);
  const actions = seat == null ? [] : (actionsBySeat[seat] ?? []);

  useEffect(() => {
    if (guoSeat != null && !(actionsBySeat[guoSeat] ?? []).includes('GUO')) setGuoSeat(undefined);
  }, [actionsBySeat, guoSeat]);

  const action = (a: any) => send({ type: 'ACTION', action: a });
  const joinFourTestSeats = () => {
    const roomId = room;
    for (let i = 0; i < 4; i++) send({ type: 'JOIN', roomId, name: `${name}-${i}` });
  };

  return <div className="app">
    <h1>通辽麻掌儿 第一版</h1>
    <div className="panel join">
      <input value={name} onChange={e => setName(e.target.value)} placeholder="昵称" />
      <input value={room} onChange={e => setRoom(e.target.value)} placeholder="房间号" />
      <button onClick={() => send({ type: 'CREATE_ROOM' })}>创建房间</button>
      <button onClick={() => send({ type: 'JOIN', roomId: room, name })}>加入一个玩家/座位</button>
      <button onClick={joinFourTestSeats}>一键加入四个测试玩家</button>
      <button disabled={!canStart && state?.phase === 'waiting'} onClick={() => send({ type: 'START', roomId: room })}>
        {state?.phase === 'waiting' ? '开始游戏' : '重新开局'}
      </button>
      <button disabled={!canUndo} onClick={() => send({ type: 'UNDO', roomId: room })}>撤回上一步</button>
      <span>{msg}</span>
    </div>
    {state && <>
      <div className="panel status">
        四家同屏测试模式｜房间 {state.roomId}｜第 {state.round} 局｜人数 {connectedCount}/4｜本网页可操作座位 {controlledSeats.join(',') || '-'}｜阶段 {state.phase}｜基数 {state.baseScore}｜当前出牌座位 {state.currentSeat}｜
        {state.pendingXiSupplement ? '晾喜中/待结束补牌' : state.turnDrawn ? '可打牌' : '可亮喜/待摸牌'}｜庄 {state.dealerSeat}｜翻牌 <MiniTile tile={state.revealedFishTile} />｜鱼 <MiniTile tile={state.fishTile} />｜剩余 {state.wall.length}｜赢家 {state.winnerSeat ?? '-'}
      </div>
      {controlledSeats.length > 1 && <div className="panel ops"><b>四家同屏：</b>下面每个玩家框内都有自己的操作区，不需要切换控制座位。</div>}
      {state.phase === 'waiting' && <div className="panel ops"><h2>{connectedCount === 4 ? '四人已到齐' : `等待玩家加入：${connectedCount}/4`}</h2><p>测试版本默认显示所有人的牌。四个人都加入后点击“开始游戏”，进入本局基数、扎针、买鱼设置。</p><button disabled={!canStart} onClick={() => send({ type: 'START', roomId: room })}>开始游戏</button></div>}
      {state.phase === 'betting' && <div className="panel ops betting"><h2>本局设置</h2><p>庄家设置基数；每个玩家直接在这里确认。全员确认后自动发牌开局。</p>{controlledSeats.includes(state.dealerSeat) && <span>基数 <input type="number" min="1" value={baseInput} onChange={e => setBaseInput(Number(e.target.value) || 1)} /><button onClick={() => action({ type: 'SET_BASE', seat: state.dealerSeat, baseScore: baseInput })}>设置基数</button><button onClick={() => { setBaseInput(1); action({ type: 'SET_BASE', seat: state.dealerSeat, baseScore: 1 }); }}>1分</button><button onClick={() => { setBaseInput(2); action({ type: 'SET_BASE', seat: state.dealerSeat, baseScore: 2 }); }}>2分</button><button onClick={() => { setBaseInput(5); action({ type: 'SET_BASE', seat: state.dealerSeat, baseScore: 5 }); }}>5分</button></span>}<div>当前基数：{state.baseScore}</div><label><input type="checkbox" checked={zhaInput} onChange={e => setZhaInput(e.target.checked)} /> 扎针</label><label> 买鱼 <input type="number" min="0" value={buyFishInput} onChange={e => setBuyFishInput(Math.max(0, Number(e.target.value) || 0))} /> 条</label><div>{controlledSeats.map(s => <button key={s} disabled={state.bets[s]?.ready} onClick={() => action({ type: 'SET_BET', seat: s, zha: zhaInput, buyFish: buyFishInput })}>玩家{s}确认</button>)}</div><div>{state.players.map(p => <span className="bet-chip" key={p.seat}>玩家{p.seat}: {state.bets[p.seat]?.ready ? '已确认' : '未确认'} {state.bets[p.seat]?.zha ? '扎针' : '不扎'} 买{state.bets[p.seat]?.buyFish ?? 0}鱼</span>)}</div></div>}
      {state.phase === 'settlement' && <SettlementPanel state={state} controlledSeats={controlledSeats} onAction={action} />}
      {guoSeat != null && <div className="panel guo-tip">玩家{guoSeat}过牌模式：可过的牌正常显示，不能过的牌会变暗且不能点击。点一张只过一张；补牌后如果还有可过牌会继续留在这里，不想过了点“结束过牌”。</div>}
      <div className="table">
        {state.players.map(p => {
          const isControlled = controlledSeats.includes(p.seat);
          const playerActions = actionsBySeat[p.seat] ?? [];
          const playerGuoTiles = new Set(p.hand.filter(t => canGuoTileClient(p, t, state.fishTile)));
          const playerChiOptions = legalChiOptionsClient(p.hand, state.lastDiscard?.tile, p.seat, state.lastDiscard?.seat, state.lastDiscard?.source, state.fishTile);
          const canDiscard = isControlled && playerActions.includes('DISCARD') && guoSeat !== p.seat;
          const canGuo = isControlled && playerActions.includes('GUO') && guoSeat === p.seat;
          return <div key={p.seat} className={'player ' + (isControlled ? 'me' : '') + (p.seat === state.currentSeat ? ' current' : '')}>
            <div className="player-head">
              <h3>{p.seat} {p.name} {p.connected ? '●' : '○'}</h3>
              <div className="score-box">积分 {state.scores[p.seat]}</div>
            </div>
            <div className="section-title">弃牌</div>
            <Tiles tiles={p.discarded} fish={state.fishTile} />
            <MeldArea player={p} fish={state.fishTile} />
            <div className="section-title">手牌 {p.hand.length}</div>
            <Tiles
              tiles={p.hand}
              fish={state.fishTile}
              drawn={state.drawnTile?.seat === p.seat ? state.drawnTile.tile : undefined}
              sort
              clickable={canDiscard || canGuo}
              canClickTile={canGuo ? (t => playerGuoTiles.has(t)) : undefined}
              dimUnclickable={canGuo}
              onClick={t => canGuo ? action({ type: 'GUO', seat: p.seat, tile: t }) : action({ type: 'DISCARD', seat: p.seat, tile: t })}
            />
            {isControlled && <SeatActionPanel state={state} actionsBySeat={actionsBySeat} seat={p.seat} actions={playerActions} chiOptions={playerChiOptions} guoMode={guoSeat === p.seat} onGuoMode={v => setGuoSeat(v ? p.seat : undefined)} onAction={action} />}
          </div>;
        })}
      </div>
      <div className="panel ops"><b>操作提示：</b>每个玩家自己的操作按钮已经放进对应玩家框内；能响应吃/碰/杠/胡的人会在自己的框里直接出现按钮。无人响应时服务端会自动给下家摸牌。</div>
      <div className="panel log"><b>本局日志（最近20条）</b><div>全房间持久日志：<a href={`http://${location.hostname || 'localhost'}:8787/rooms/${state.roomId}/logs`} target="_blank">打开/另存 JSON</a>；服务端同时写入 logs/room-{state.roomId}.jsonl</div>{state.log.slice(-20).map((l, i) => <pre key={i}>{JSON.stringify(l)}</pre>)}</div>
    </>}
  </div>;
}

function MiniTile({ tile }: { tile: Tile }) {
  return <span className="mini-tile"><img src={tileImage(tile)} alt={label(tile)} />{label(tile)}</span>;
}

function SeatActionPanel({ state, actionsBySeat, seat, actions, chiOptions, guoMode, onGuoMode, onAction }: { state: GameState; actionsBySeat: Record<number, string[]>; seat: number; actions: string[]; chiOptions: Tile[][]; guoMode: boolean; onGuoMode: (v: boolean) => void; onAction: (a: any) => void }) {
  const p = state.players[seat];
  const hasAction = actions.length > 0;
  const canResolve = (type: string) => canResolveResponseAction(state, actionsBySeat, seat, type);
  const waitingHigher = state.phase === 'responding' && ['HU','MING_GANG','PENG','CHI'].some(a => actions.includes(a) && !canResolve(a));
  return <div className="seat-actions">
    <div className="section-title">玩家{seat}操作：{hasAction ? actions.join(', ') : '无'}</div>
    {state.phase === 'responding' && actions.includes('PASS') && <button onClick={() => onAction({ type: 'PASS', seat })}>过响应</button>}
    <button disabled={!actions.includes('HU') || !canResolve('HU')} onClick={() => onAction({ type: 'HU', seat })}>胡</button>
    {actions.includes('CHI') && chiOptions.length > 1
      ? <span className="chi-options">吃法：{chiOptions.map((opt, i) => <button key={i} disabled={!canResolve('CHI')} onClick={() => onAction({ type: 'CHI', seat, tiles: opt })}>{opt.map(label).join(' ')}</button>)}</span>
      : <button disabled={!actions.includes('CHI') || !canResolve('CHI')} onClick={() => onAction({ type: 'CHI', seat, tiles: chiOptions[0] })}>吃{chiOptions[0] ? ':' + chiOptions[0].map(label).join(' ') : ''}</button>}
    <button disabled={!actions.includes('PENG') || !canResolve('PENG')} onClick={() => onAction({ type: 'PENG', seat })}>碰</button>
    <button disabled={!actions.includes('MING_GANG') || !canResolve('MING_GANG')} onClick={() => onAction({ type: 'MING_GANG', seat })}>明杠</button>
    <button disabled={!actions.includes('BU_GANG')} onClick={() => onAction({ type: 'BU_GANG', seat })}>补杠</button>
    <button disabled={!actions.includes('AN_GANG')} onClick={() => onAction({ type: 'AN_GANG', seat })}>暗杠</button>
    {!guoMode && <button disabled={!actions.includes('GUO')} onClick={() => onGuoMode(true)}>过牌</button>}
    {guoMode && <button onClick={() => onGuoMode(false)}>结束过牌</button>}
    <button disabled={!actions.includes('END_XI')} onClick={() => onAction({ type: 'END_XI', seat })}>结束晾喜/补一张</button>
    <XiButtons hand={p.hand} fish={state.fishTile} enabled={actions.includes('DECLARE_XI')} onXi={name => onAction({ type: 'DECLARE_XI', seat, name })} />
    {waitingHigher && <span className="hint">等待更高优先级/前位响应先过</span>}
    {actions.includes('DISCARD') && <span className="hint">点手牌出牌</span>}
    <button disabled={!actions.includes('DRAW')} onClick={() => onAction({ type: 'DRAW', seat })}>不晾喜/摸牌</button>
    <button disabled={!actions.includes('FENZHANG')} onClick={() => onAction({ type: 'FENZHANG', seat })}>进入分张儿</button>
  </div>;
}

function SettlementPanel({ state, controlledSeats, onAction }: { state: GameState; controlledSeats: number[]; onAction: (a: any) => void }) {
  const st = state.settlement;
  return <div className="panel settlement"><h2>本局结算</h2>{st ? <>
    <div>赢家：玩家{st.winnerSeat}｜{st.selfDraw ? '自摸' : `点炮：玩家${st.discarderSeat}`}｜基数：{st.baseScore}｜鱼：自己{st.ownFish}+买鱼总数{st.boughtFishTotal}=总鱼{st.fishTotal}｜扎针：{st.zhaSeats.join(',') || '无'}</div>
    <table><thead><tr><th>玩家</th><th>原积分</th><th>本局</th><th>现积分</th></tr></thead><tbody>{st.deltas.map(d => <tr key={d.seat}><td>{d.seat} {state.players[d.seat]?.name}</td><td>{d.before}</td><td className={d.delta >= 0 ? 'plus' : 'minus'}>{d.delta > 0 ? '+' : ''}{d.delta}</td><td>{d.after}</td></tr>)}</tbody></table>
  </> : <div>等待结算数据</div>}
    <div>{controlledSeats.map(s => <button key={s} disabled={state.readyNext[s]} onClick={() => onAction({ type: 'NEXT_ROUND', seat: s })}>玩家{s}{state.readyNext[s] ? '已准备' : '下一局'}</button>)}</div>
    <div>下一局准备：{state.players.map(p => <span className="bet-chip" key={p.seat}>玩家{p.seat}:{state.readyNext[p.seat] ? '已点' : '未点'}</span>)}</div></div>;
}

function Tiles({ tiles, fish, sort, drawn, clickable, onClick, canClickTile, dimUnclickable }: { tiles: Tile[]; fish: Tile; sort?: boolean; drawn?: Tile; clickable?: boolean; onClick?: (t: Tile) => void; canClickTile?: (t: Tile) => boolean; dimUnclickable?: boolean }) {
  const shown = sort ? tilesForView(tiles, fish, drawn) : tiles.map(tile => ({ tile, drawn: false }));
  return <div className="tiles">{shown.map(({ tile: t, drawn: isDrawn }, i) => {
    const canClick = !!clickable && t !== 'BACK' && (!canClickTile || canClickTile(t));
    const dim = !!dimUnclickable && !canClick;
    return <button className={'tile ' + (isDrawn ? 'drawn' : '') + ' ' + (t === fish ? 'fish' : '') + ' ' + (dim ? 'dimmed' : '')} title={label(t)} disabled={!canClick} key={`${t}-${i}`} onClick={() => onClick?.(t)}>{t === fish && <span className="fish-star">★</span>}<img src={tileImage(t)} alt={label(t)} /></button>;
  })}</div>;
}

function MeldArea({ player, fish }: { player: Player; fish: Tile }) {
  const xi = player.melds.filter(m => m.type === 'xi');
  const other = player.melds.filter(m => m.type !== 'xi');
  return <div className="front-area">
    <div className="front-pile"><div className="section-title">门前：喜 + 过</div>{xi.length ? xi.map((m, i) => <MeldTiles key={i} meld={m} fish={fish} />) : <span className="empty">无</span>}</div>
    <div className="front-pile"><div className="section-title">门前：吃碰杠</div>{other.length ? other.map((m, i) => <MeldTiles key={i} meld={m} fish={fish} />) : <span className="empty">无</span>}</div>
  </div>;
}

function MeldTiles({ meld, fish }: { meld: Meld; fish: Tile }) {
  return <div className="meld-set"><span className="meld-name">{meld.name ?? meld.type}</span><Tiles tiles={meld.tiles} fish={fish} /></div>;
}

const xiDefs: Array<[string, Tile[]]> = [
  ['中发白', ['Zhong', 'Fa', 'Bai']],
  ['中发鱼', ['Zhong', 'Fa', 'Fish' as Tile]],
  ['中发九', ['Zhong', 'Fa', 'T9']],
  ['鱼中白', ['Fish' as Tile, 'Zhong', 'Bai']],
  ['鱼发白', ['Fish' as Tile, 'Fa', 'Bai']],
  ['鱼中九', ['Fish' as Tile, 'Zhong', 'T9']],
  ['鱼发九', ['Fish' as Tile, 'Fa', 'T9']],
  ['鱼钩白', ['Fish' as Tile, 'T9', 'Bai']],
  ['中八叉', ['Zhong', 'W8', 'T5']],
  ['鱼八叉', ['Fish' as Tile, 'W8', 'T5']],
  ['老虎喜儿', ['Fish' as Tile, 'W1', 'B9']],
  ['幺八白', ['W1', 'W8', 'Bai']],
  ['幺二拐', ['W1', 'T2', 'B7']],
  ['江里蹦', ['W9', 'T8', 'Bai']],
  ['万钩千', ['W1', 'T9', 'Fa']],
  ['幺喜儿', ['Fish' as Tile, 'W1', 'B1']],
  ['五喜儿', ['T5', 'W5', 'B5']],
  ['九喜儿', ['T9', 'W9', 'B9']],
  ['中九九', ['Zhong', 'W9', 'T9']],
];

function logicalTile(tile: Tile, fish: Tile): Tile {
  if (tile === fish) return 'T1';
  if (tile === 'T1' && fish !== 'T1') return fish;
  return tile;
}

function findXiNamesForButtons(hand: Tile[], fish: Tile) {
  const baseCounts = new Map<Tile, number>();
  for (const tile of hand) baseCounts.set(tile, (baseCounts.get(tile) ?? 0) + 1);
  const names: string[] = [];
  for (const [name, pattern] of xiDefs) {
    const remaining = new Map(baseCounts);
    let ok = true;
    for (const token of pattern) {
      if (token === 'Fish') {
        if ((remaining.get(fish) ?? 0) <= 0) { ok = false; break; }
        remaining.set(fish, (remaining.get(fish) ?? 0) - 1);
        continue;
      }
      const actual = Array.from(remaining.keys()).find(tile => (remaining.get(tile) ?? 0) > 0 && matchesXiPatternTokenClient(tile, token, fish));
      if (!actual) { ok = false; break; }
      remaining.set(actual, (remaining.get(actual) ?? 0) - 1);
    }
    if (ok) names.push(name);
  }
  return names;
}

function XiButtons({ hand, fish, enabled, onXi }: { hand: Tile[]; fish: Tile; enabled: boolean; onXi: (n: string) => void }) {
  const names = findXiNamesForButtons(hand, fish);
  return <>{names.map(n => <button key={n} disabled={!enabled} onClick={() => onXi(n)}>亮喜:{n}</button>)}</>;
}

createRoot(document.getElementById('root')!).render(<App />);
